import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import { phieuTamTruAPI, phongAPI } from '../services/api';
import {
  buildCt01PreviewData,
  CT01_NOTES,
  downloadCt01Doc,
  formatDateVN,
} from '../utils/phieuTamTruDocument';
import './PhieuTamTru.css';

const normalizeName = value => value.trim().replace(/\s+/g, ' ');
const isValidName = value => {
  const normalized = normalizeName(value);
  return normalized.length >= 2 && normalized.length <= 100 && !/\d/.test(normalized);
};
const isValidPhone = value => value === '' || /^\d{10,11}$/.test(value);

const createInitialForm = user => ({
  maPhong: '',
  hoTen: user?.hoTenXacThuc || user?.hoTen || '',
  soDienThoai: user?.soDienThoai || '',
  ngaySinh: user?.ngaySinhXacThuc || '',
  diaChiThuongTru: user?.diaChiThuongTruXacThuc || '',
  ngayBatDau: '',
});

function FilledLine({ value, className = '' }) {
  return (
    <span className={`ct01-fill ${value ? '' : 'is-empty'} ${className}`.trim()}>
      {value || '\u00A0'}
    </span>
  );
}

function SignatureBlock({ title, dateText, signerName = '' }) {
  return (
    <div className="ct01-signature-block">
      <div className="ct01-date">{dateText}</div>
      <div className="ct01-signature-title">{title}</div>
      <div className="ct01-signature-note">(Ký, ghi rõ họ tên)</div>
      <div className="ct01-signature-space" />
      <div className="ct01-signature-name">{signerName}</div>
    </div>
  );
}

function CT01Preview({ data }) {
  const preview = buildCt01PreviewData(data);

  return (
    <div className="ct01-sheet">
      <div className="ct01-header">
        <div className="ct01-header-left">
          Mẫu CT01 ban hành kèm theo Thông tư số 66/2023/TT-BCA ngày 17/11/2023
          của Bộ trưởng Bộ Công an
        </div>
        <div className="ct01-header-right">
          <div className="ct01-national-title">CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</div>
          <div className="ct01-national-motto">Độc lập - Tự do - Hạnh phúc</div>
          <div className="ct01-national-line" />
        </div>
      </div>

      <h2 className="ct01-title">TỜ KHAI THAY ĐỔI THÔNG TIN CƯ TRÚ</h2>
      <p className="ct01-subtitle">Bản xem trước biểu mẫu CT01 từ FindRoomMate</p>

      <div className="ct01-line">
        <strong>Kính gửi(1):</strong>
        <FilledLine value={preview.coQuanDangKy} />
      </div>

      <div className="ct01-two-column">
        <div className="ct01-field">
          <strong>1. Họ, chữ đệm và tên:</strong>
          <FilledLine value={preview.hoTen} />
        </div>
        <div className="ct01-field">
          <strong>2. Ngày, tháng, năm sinh:</strong>
          <FilledLine value={preview.ngaySinhText} />
        </div>
        <div className="ct01-field">
          <strong>3. Giới tính:</strong>
          <FilledLine value="" />
        </div>
        <div className="ct01-field">
          <strong>4. Số định danh cá nhân:</strong>
          <FilledLine value={preview.soCanCuocCongDan} />
        </div>
        <div className="ct01-field">
          <strong>5. Số điện thoại liên hệ:</strong>
          <FilledLine value={preview.soDienThoai} />
        </div>
        <div className="ct01-field">
          <strong>6. Email:</strong>
          <FilledLine value={preview.email} />
        </div>
        <div className="ct01-field">
          <strong>7. Họ, chữ đệm và tên chủ hộ:</strong>
          <FilledLine value={preview.tenChuHo} />
        </div>
        <div className="ct01-field">
          <strong>8. Mối quan hệ với chủ hộ:</strong>
          <FilledLine value={preview.quanHeVoiChuHo} />
        </div>
        <div className="ct01-field">
          <strong>9. Số định danh cá nhân của chủ hộ:</strong>
          <FilledLine value="" />
        </div>
        <div className="ct01-field">
          <strong>Địa chỉ thường trú:</strong>
          <FilledLine value={preview.diaChiThuongTru} />
        </div>
      </div>

      <div className="ct01-line">
        <strong>10. Nội dung đề nghị(2):</strong>
        <div className={`ct01-long-fill ${preview.noiDungDeNghi ? '' : 'is-empty'}`.trim()}>
          {preview.noiDungDeNghi || '\u00A0'}
        </div>
      </div>

      <div className="ct01-line">
        <strong>11. Những thành viên trong hộ gia đình cùng thay đổi:</strong>
        <table className="ct01-table">
          <thead>
            <tr>
              <th style={{ width: '9%' }}>TT</th>
              <th>Họ, chữ đệm và tên</th>
              <th style={{ width: '18%' }}>Ngày, tháng, năm sinh</th>
              <th style={{ width: '20%' }}>Số định danh cá nhân</th>
              <th style={{ width: '18%' }}>Mối quan hệ với chủ hộ</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td style={{ textAlign: 'center' }}>1</td>
              <td />
              <td />
              <td />
              <td />
            </tr>
          </tbody>
        </table>
      </div>

      <div className="ct01-signatures">
        <SignatureBlock title="Ý KIẾN CỦA CHỦ HỘ(3)" dateText={preview.ngayKyText} />
        <SignatureBlock title="Ý KIẾN CỦA CHỦ SỞ HỮU CHỖ Ở HỢP PHÁP(4)" dateText={preview.ngayKyText} />
      </div>
      <div className="ct01-signatures">
        <SignatureBlock title="Ý KIẾN CỦA CHA, MẸ HOẶC NGƯỜI GIÁM HỘ(5)" dateText={preview.ngayKyText} />
        <SignatureBlock title="NGƯỜI KÊ KHAI(6)" dateText={preview.ngayKyText} signerName={preview.hoTen} />
      </div>

      <div className="ct01-notes">
        <strong>Chú thích:</strong>
        {CT01_NOTES.map(note => (
          <p key={note}>{note}</p>
        ))}
      </div>
    </div>
  );
}

export default function PhieuTamTru() {
  const { user } = useAuthStore();
  const [phieus, setPhieus] = useState([]);
  const [phongs, setPhongs] = useState([]);
  const [form, setForm] = useState(() => createInitialForm(null));
  const [tab, setTab] = useState('list');
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(true);
  const [selectedPhieuId, setSelectedPhieuId] = useState(null);

  const setField = (key, value) => setForm(current => ({ ...current, [key]: value }));

  useEffect(() => {
    let active = true;

    const loadData = async () => {
      try {
        const [phieuRes, phongRes] = await Promise.all([
          phieuTamTruAPI.layCuaToi(),
          phongAPI.layPhongCuaToi(),
        ]);

        if (!active) return;

        const nextPhieus = phieuRes.data.data || [];
        setPhieus(nextPhieus);
        setPhongs(phongRes.data.data || []);
        setSelectedPhieuId(nextPhieus[0]?.maPhieuTamTru || null);
      } catch (error) {
        if (active) {
          toast.error('Không tải được dữ liệu phiếu tạm trú');
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    };

    loadData();

    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    if (!user) return;

    setForm(current => ({
      ...current,
      hoTen: current.hoTen || user.hoTenXacThuc || user.hoTen || '',
      soDienThoai: current.soDienThoai || user.soDienThoai || '',
      ngaySinh: current.ngaySinh || user.ngaySinhXacThuc || '',
      diaChiThuongTru: current.diaChiThuongTru || user.diaChiThuongTruXacThuc || '',
    }));
  }, [user]);

  const resetForm = () => {
    setForm(createInitialForm(user));
  };

  const selectedPhong = phongs.find(phong => String(phong.maPhong) === String(form.maPhong));
  const selectedPhieu = phieus.find(phieu => phieu.maPhieuTamTru === selectedPhieuId) || phieus[0] || null;

  const previewData = {
    ...form,
    email: user?.email || '',
    soCanCuocCongDan: user?.soCanCuocCongDan || '',
    tenPhong: selectedPhong?.title || '',
    diaChiTamTru: selectedPhong?.diaChiDayDu || '',
    tenChuHo: selectedPhong?.tenChuPhong || '',
    quanHeVoiChuHo:
      selectedPhong && user
        ? selectedPhong.maChuPhong === user.maNguoiDung
          ? 'Chủ hộ'
          : 'Người thuê'
        : '',
  };

  const handleSubmit = async event => {
    event.preventDefault();

    const hoTen = normalizeName(form.hoTen);

    if (!isValidName(hoTen)) {
      toast.error('Họ tên phải từ 2 đến 100 ký tự và không được chứa số');
      return;
    }

    if (!isValidPhone(form.soDienThoai)) {
      toast.error('Số điện thoại phải gồm 10 hoặc 11 chữ số');
      return;
    }

    if (form.ngaySinh && new Date(form.ngaySinh) > new Date()) {
      toast.error('Ngày sinh không được lớn hơn ngày hiện tại');
      return;
    }

    setSubmitting(true);
    try {
      const createRes = await phieuTamTruAPI.tao({
        ...form,
        hoTen,
        maPhong: parseInt(form.maPhong, 10),
      });

      const createdPhieu = createRes.data.data;
      const listRes = await phieuTamTruAPI.layCuaToi();
      const nextPhieus = listRes.data.data || [];

      setPhieus(nextPhieus);
      setSelectedPhieuId(createdPhieu?.maPhieuTamTru || nextPhieus[0]?.maPhieuTamTru || null);
      resetForm();
      setTab('list');
      toast.success('Tạo phiếu tạm trú thành công');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Không thể tạo phiếu tạm trú');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="container page-wrapper">
      <div className="phieu-page-header">
        <div>
          <h1 className="section-title">Phiếu tạm trú</h1>
          <p className="section-subtitle">
            Kê khai theo mẫu CT01 và tải xuống file Word có sẵn nội dung để in hoặc bổ sung chữ ký.
          </p>
        </div>
        <div className="phieu-brand-pill">FindRoomMate</div>
      </div>

      <div className="tabs">
        {[
          ['list', 'Danh sách phiếu'],
          ['new', 'Tạo phiếu mới'],
        ].map(([key, label]) => (
          <div
            key={key}
            className={`tab ${tab === key ? 'active' : ''}`}
            onClick={() => setTab(key)}
          >
            {label}
          </div>
        ))}
      </div>

      {tab === 'list' && (
        loading ? (
          <div className="card">
            <div className="card-body">Đang tải phiếu tạm trú...</div>
          </div>
        ) : phieus.length === 0 ? (
          <div className="empty-state">
            <div className="empty-state-icon">CT01</div>
            <p>Bạn chưa có phiếu tạm trú nào.</p>
          </div>
        ) : (
          <div className="phieu-dashboard">
            <div className="card phieu-list-panel">
              <div className="card-header">Phiếu đã tạo</div>
              <div className="card-body phieu-list-body">
                {phieus.map(phieu => (
                  <button
                    key={phieu.maPhieuTamTru}
                    type="button"
                    className={`phieu-list-item ${selectedPhieu?.maPhieuTamTru === phieu.maPhieuTamTru ? 'active' : ''}`.trim()}
                    onClick={() => setSelectedPhieuId(phieu.maPhieuTamTru)}
                  >
                    <strong>#{phieu.maPhieuTamTru} • {phieu.hoTen}</strong>
                    <span>{phieu.tenPhong || 'Chưa chọn phòng'}</span>
                    <span>Tạm trú từ {formatDateVN(phieu.ngayBatDau) || 'chưa cập nhật'}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="phieu-preview-panel">
              <div className="phieu-preview-actions">
                <div>
                  <h3>Mẫu CT01 đã điền</h3>
                  <p>
                    Một số mục như giới tính, cơ quan đăng ký hoặc số định danh của chủ hộ sẽ để trống nếu hệ thống
                    chưa có dữ liệu.
                  </p>
                </div>
                <button
                  type="button"
                  className="btn btn-primary"
                  onClick={() => downloadCt01Doc(selectedPhieu)}
                >
                  Tải mẫu CT01 (.doc)
                </button>
              </div>

              {selectedPhieu && <CT01Preview data={selectedPhieu} />}
            </div>
          </div>
        )
      )}

      {tab === 'new' && (
        <div className="phieu-editor">
          <div className="card phieu-form-card">
            <div className="card-header">Khai báo thông tin tạm trú</div>
            <div className="card-body">
              <div className="alert alert-info">
                FindRoomMate sẽ tự điền họ tên, CCCD, ngày sinh, email và địa chỉ thường trú từ hồ sơ đã xác thực nếu có.
              </div>

              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <label className="form-label">Chọn phòng *</label>
                  <select
                    className="form-control"
                    required
                    value={form.maPhong}
                    onChange={event => setField('maPhong', event.target.value)}
                  >
                    <option value="">-- Chọn phòng --</option>
                    {phongs.map(phong => (
                      <option key={phong.maPhong} value={phong.maPhong}>
                        {phong.title} - {phong.diaChiDayDu || 'Chưa có địa chỉ'}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="grid-2">
                  <div className="form-group">
                    <label className="form-label">Họ và tên *</label>
                    <input
                      className="form-control"
                      required
                      maxLength={100}
                      value={form.hoTen}
                      onChange={event => setField('hoTen', event.target.value)}
                    />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Số điện thoại</label>
                    <input
                      className="form-control"
                      inputMode="numeric"
                      pattern="[0-9]{10,11}"
                      maxLength={11}
                      value={form.soDienThoai}
                      onChange={event => setField('soDienThoai', event.target.value.replace(/\D/g, ''))}
                    />
                  </div>
                </div>

                <div className="grid-2">
                  <div className="form-group">
                    <label className="form-label">Ngày sinh</label>
                    <input
                      className="form-control"
                      type="date"
                      value={form.ngaySinh}
                      onChange={event => setField('ngaySinh', event.target.value)}
                    />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Ngày bắt đầu tạm trú *</label>
                    <input
                      className="form-control"
                      type="date"
                      required
                      value={form.ngayBatDau}
                      onChange={event => setField('ngayBatDau', event.target.value)}
                    />
                  </div>
                </div>

                <div className="form-group">
                  <label className="form-label">Địa chỉ thường trú</label>
                  <input
                    className="form-control"
                    value={form.diaChiThuongTru}
                    onChange={event => setField('diaChiThuongTru', event.target.value)}
                  />
                </div>

                <div className="phieu-form-actions">
                  <button type="submit" className="btn btn-primary btn-lg" disabled={submitting}>
                    {submitting ? 'Đang tạo...' : 'Lưu phiếu tạm trú'}
                  </button>
                  <button
                    type="button"
                    className="btn btn-outline btn-lg"
                    disabled={!form.maPhong || !previewData.hoTen}
                    onClick={() => downloadCt01Doc(previewData)}
                  >
                    Tải bản xem trước (.doc)
                  </button>
                </div>
              </form>
            </div>
          </div>

          <div className="phieu-preview-panel">
            <div className="phieu-preview-actions">
              <div>
                <h3>Xem trước mẫu CT01</h3>
                <p>Mẫu tải xuống sẽ giữ nguyên bố cục như phần xem trước bên dưới.</p>
              </div>
            </div>

            <CT01Preview data={previewData} />
          </div>
        </div>
      )}
    </div>
  );
}
